from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/health')
def health_check():
    response = {
        "status": "UP",
        "service": "MyApplication",
        "timestamp": Flask.timestamp() # In a real app, this would be more robust
    }
    return jsonify(response), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)
